+
+    #[test]
+    fn overlay_renders_children() {
+        let mut debugger = LayoutDebugger::new();
+        debugger.set_enabled(true);
+
+        let child = LayoutRecord::new(
+            "Child",
+            Rect::new(2, 2, 4, 2),
+            Rect::new(2, 2, 4, 2),
+            LayoutConstraints::unconstrained(),
